// Mode: Run Once for All Items
const items = $input.all().map(i => i.json).flat();

const parseReview = (texto) => {
  if (!texto || typeof texto !== 'string') {
    return { nota: null, justificativa: null };
  }
  if (texto.trim() === '77') {
    return { nota: 'insuficiente', justificativa: null };
  }
  const idx = texto.indexOf(':');

  // SEM dois-pontos: pode ser nota seca tipo "8.0" -> trata como nota
  if (idx === -1) {
    const soNota = texto.trim().replace(',', '.');
    if (/^\d{1,2}(\.\d+)?$/.test(soNota)) {
      const n = parseFloat(soNota);
      return { nota: isNaN(n) ? null : n, justificativa: null };
    }
    return { nota: null, justificativa: texto.trim() };
  }

  // COM dois-pontos
  const notaRaw = texto.slice(0, idx).trim().replace(',', '.');

  // "77: justificativa" -> insuficiente, preservando a justificativa
  if (notaRaw === '77') {
    return { nota: 'insuficiente', justificativa: texto.slice(idx + 1).trim() };
  }

  const nota = parseFloat(notaRaw);
  return {
    nota: isNaN(nota) ? null : nota,
    justificativa: texto.slice(idx + 1).trim(),
  };
};

const estabelecimentos = items.filter(i => i && i.nome !== undefined);
const reviewItems = items.filter(i => {
  if (!i || i.nome !== undefined) return false;
  const k = Object.keys(i)[0];
  return k && k.endsWith('_review');
});

const reviewsPorId = /** @type {Record<string, any>} */ ({});
for (const item of reviewItems) {
  const [chave, valorBruto] = Object.entries(item)[0];
  const nomeAtributo = chave.replace(/_review$/, '');
  try {
    const dadosIA = JSON.parse(valorBruto);
    const idEstabelecimento = dadosIA.id;
    const resultadoIA = String(dadosIA.resultado || '');
    if (!idEstabelecimento) continue;
    if (!reviewsPorId[idEstabelecimento]) {
      reviewsPorId[idEstabelecimento] = { notasNum: [] };
    }
    const { nota, justificativa } = parseReview(resultadoIA);
    const alvo = reviewsPorId[idEstabelecimento];
    const chaveNota = `${nomeAtributo}_nota`;
    const chaveJust = `${nomeAtributo}_justificativa`;
    const jaTemNota = typeof alvo[chaveNota] === 'number' || alvo[chaveNota] === 'insuficiente';
    const novaTemNota = typeof nota === 'number' || nota === 'insuficiente';
    // Só grava se a chave ainda não existe OU se o novo registro traz nota.
    // Nunca deixa um item SEM nota apagar um que já tinha nota válida.
    if (!(chaveNota in alvo) || novaTemNota) {
      if (!(jaTemNota && !novaTemNota)) {
        alvo[chaveNota] = nota;
        alvo[chaveJust] = justificativa;
        if (typeof nota === 'number') {
          if (!alvo.notasNum.includes(nota)) alvo.notasNum.push(nota);
        }
      }
    }
  } catch (error) {
    continue;
  }
}

const summaryPorId = /** @type {Record<string, string>} */ ({});
for (const item of items) {
  if (!item || !item.summary) continue;
  try {
    const dados = JSON.parse(item.summary);
    if (dados.id && dados.resultado) {
      summaryPorId[dados.id] = dados.resultado;
    }
  } catch (error) {
    continue;
  }
}

return estabelecimentos.map(est => {
  const idAtual = est.id;
  const dadosDoEstabelecimento = reviewsPorId[idAtual] || { notasNum: [] };
  const arrayDeNotas = dadosDoEstabelecimento.notasNum;
  const media = arrayDeNotas.length
    ? Math.round((arrayDeNotas.reduce((a, b) => a + b, 0) / arrayDeNotas.length) * 100) / 100
    : null;
  delete dadosDoEstabelecimento.notasNum;
  return {
    json: {
      ...est,
      ...dadosDoEstabelecimento,
      resumo: summaryPorId[idAtual] || est.resumo || null,
      media_reviews: media,
    }
  };
});

// Mode: Run Once for All Items
// Mantém todos os campos do estabelecimento e ADICIONA comentarios_formatados:
// todos os comentários juntos numa string, indicando cliente x resposta do dono.

const items = $input.all();

return items.map((item) => {
  const e = item.json || {};

  // "reviews" vem como STRING JSON — parseia
  let reviews = [];
  try {
    reviews = typeof e.reviews === "string" ? JSON.parse(e.reviews) : (e.reviews || []);
  } catch (err) {
    reviews = [];
  }
  if (!Array.isArray(reviews)) reviews = [];

  // Monta o bloco de comentários, separados e numerados,
  // com a resposta do dono identificada quando existir.
  const comentarios_formatados = reviews
    .filter((r) => r && r.review_text)
    .map((r, idx) => {
      const nota = r.review_rate ?? "?";
      const texto = String(r.review_text).replace(/\s+/g, " ").trim();

      let bloco = `Comentário ${idx + 1} (nota ${nota}) [CLIENTE]: ${texto}`;

      const resp = r.business_response_text;
      if (resp && String(resp).trim()) {
        const respLimpa = String(resp).replace(/\s+/g, " ").trim();
        bloco += `\n   ↳ [RESPOSTA DO DONO]: ${respLimpa}`;
      }

      return bloco;
    })
    .join("\n\n");

  return {
    json: {
      ...e,                      // mantém TODOS os campos originais do estabelecimento
      comentarios_formatados,    // adiciona o bloco de comentários
    },
  };
});

// Mode: Run Once for All Items
// Para cada estabelecimento do input, busca infos (/place.php) + reviews (/reviews.php).

const RAPIDAPI_HOST = "maps-data.p.rapidapi.com";
const RAPIDAPI_KEY = "5958443742msh4dc98515842ccdep1d2710jsn24c8576398c6";

const COUNTRY = "br";
const LANG = "pt";

const headers = {
  "Content-Type": "application/json",
  "x-rapidapi-host": RAPIDAPI_HOST,
  "x-rapidapi-key": RAPIDAPI_KEY,
};

// monta query string sem URLSearchParams (não existe no Code node)
function montarQuery(params) {
  return Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null && v !== "")
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
    .join("&");
}

async function chamar(path, params) {
  const url = `https://${RAPIDAPI_HOST}${path}?${montarQuery(params)}`;
  try {
    const data = await this.helpers.httpRequest({ method: "GET", url, headers, json: true });
    return { ok: true, data };
  } catch (err) {
    return { ok: false, status: err.statusCode, msg: err.response?.body || err.message, url };
  }
}

const items = $input.all();
const resultados = [];

for (const item of items) {
  const e = item.json || {};
  const BUSINESS_ID = e.google_id;
  const PLACE_ID = e.place_id;

  if (!BUSINESS_ID && !PLACE_ID) {
    resultados.push({ json: { ...e, infos: null, reviews: null, debug: { erro: "sem google_id/place_id" } } });
    continue;
  }

  // 1. Infos gerais — place.php aceita os dois ids
  const infos = await chamar.call(this, "/place.php", {
    business_id: BUSINESS_ID,
    place_id: PLACE_ID,
    country: COUNTRY,
    lang: LANG,
  });

  // 2. Reviews — usa business_id (formato 0x...:0x...)
  const reviews = await chamar.call(this, "/reviews.php", {
    business_id: BUSINESS_ID,
    country: COUNTRY,
    lang: LANG,
    limit: "20",
    sort: "Relevant",
  });

  resultados.push({
    json: {
      ...e,
      infos:   infos.ok   ? infos.data   : null,
      reviews: reviews.ok ? reviews.data : null,
      debug: {
        infos:   infos.ok   ? "ok" : infos,
        reviews: reviews.ok ? "ok" : reviews,
      },
    },
  });
}

return resultados;

// Mode: Run Once for All Items
// Casa os dados frescos da API (infos/reviews) com a row do estabelecimento por place_id.
// Preserva crated_at, id e análises. Passa adiante na automação.

const items = $input.all().map((i) => i.json || {});

// helper: extrai o objeto do place de dentro de infos (pode ser array ou objeto)
function extrairPlace(infos) {
  if (!infos) return null;
  const d = infos.data ?? infos;
  return Array.isArray(d) ? (d[0] || null) : (d || null);
}

// helper: extrai a lista de reviews de dentro de reviews (pode vir {data:{reviews:[...]}})
function extrairReviews(reviews) {
  if (!reviews) return null;
  const d = reviews.data ?? reviews;
  if (Array.isArray(d)) return d;              // já é a lista
  if (d && Array.isArray(d.reviews)) return d.reviews; // {data:{reviews:[...]}}
  return null;
}

// 1ª passada: indexa os dados FRESCOS por place_id
// (só considera "fresco" o objeto que realmente tem infos vindo da API)
const frescosPorPlace = {};
for (const e of items) {
  const place = extrairPlace(e.infos);
  if (place && e.place_id) {
    frescosPorPlace[e.place_id] = {
      place,
      reviews: extrairReviews(e.reviews),
    };
  }
}

// 2ª passada: monta o resultado, deduplicando por place_id
const fresco = (valor, antigo) =>
  valor !== undefined && valor !== null && valor !== "" ? valor : antigo;

const vistos = {};
for (const e of items) {
  const chave = e.place_id || e.id;
  if (vistos[chave]) continue; // já montou essa place_id, pula duplicata

  const dadosFrescos = frescosPorPlace[e.place_id];
  const place = dadosFrescos?.place || null;
  const listaReviews = dadosFrescos?.reviews || null;

  let atualizado;
  if (place) {
    // tem dado fresco pra essa place_id -> sobrescreve
    atualizado = {
      ...e,
      nome:             fresco(place.name, e.nome),
      endereco:         fresco(place.full_address, e.endereco),
      telefone:         fresco(place.phone_number, e.telefone),
      website:          fresco(place.website_full, e.website),
      nota:             fresco(place.rating, e.nota),
      qtd_avaliacoes:   fresco(place.review_count, e.qtd_avaliacoes),
      faixa_preco:      fresco(place.price_level, e.faixa_preco),
      link_google_maps: fresco(place.place_link, e.link_google_maps),
      nr_latitude:      fresco(place.latitude, e.nr_latitude),
      nr_longitude:     fresco(place.longitude, e.nr_longitude),
      distribuicao_notas: place.review_rates ? JSON.stringify(place.review_rates) : e.distribuicao_notas,
      horarios:         (place.working_hours && Object.keys(place.working_hours).length) ? JSON.stringify(place.working_hours) : e.horarios,
      reviews:          listaReviews ? JSON.stringify(listaReviews) : e.reviews,
      details_google:   place.details ?? null,
      atualizacoes:     new Date().toISOString(), // crated_at NÃO é tocado
    };
  } else {
    // não tem dado fresco -> mantém como está
    atualizado = { ...e };
  }

  delete atualizado.infos;
  delete atualizado.debug;

  vistos[chave] = atualizado;
}

return Object.values(vistos).map((json) => ({ json }));

// Mode: Run Once for All Items
// Passa adiante apenas a PRIMEIRA row.

const items = $input.all();
return items.length ? [items[0]] : [];

