// Mode: Run Once for Each Item — GERAL (qualquer segmento)
//
// CORREÇÃO PRINCIPAL:
// As notas chegam como STRING "insuficiente" (não como o número 77).
// O código antigo só reconhecia === 77, então "insuficiente" escapava
// da média E do tally de não-avaliadas. Agora tudo passa por normalizar():
//   - "insuficiente" / "77" / 77   -> SENTINELA (77) = sem dados
//   - número (ou "7,5" / "7.5")     -> número
//   - null / undefined / ""         -> null = não se aplica ao segmento (não conta)
//
// MÍNIMOS:
//   - food e fun  => MIN_FOOD_FUN (6 fixo)
//   - média       => MIN (vem de minimum_grade; fallback 6)
// FOOD é portão crítico: insuficiente OU nota < MIN_FOOD_FUN => reprova.
//   - PORÉM: se já reprovou por >2 insuficientes, a justificativa fica só a dos insuficientes.

const e = $input.item.json;

const SENTINELA = 77;
const MAX_NAO_AVALIADAS = 2; // acima disso (>2 => 3+) reprova
const MIN_FOOD_FUN = 6;      // mínimo fixo para comida e diversão

const ehNotaValida = (v) =>
  typeof v === "number" && Number.isFinite(v) && v !== SENTINELA;

const MIN = ehNotaValida(e.minimum_grade) ? e.minimum_grade : 6; // mínimo da média

const round = (x, d = 2) => {
  if (x === null || x === undefined || Number.isNaN(x) || !Number.isFinite(x)) {
    return null;
  }
  const f = Math.pow(10, d);
  return Math.round(x * f) / f;
};

// --------------------
// NORMALIZAÇÃO (a peça que faltava)
// --------------------
const normalizar = (v) => {
  if (v === null || v === undefined) return null;          // ausente
  if (typeof v === "number") return Number.isFinite(v) ? v : null;
  if (typeof v === "string") {
    const s = v.trim().toLowerCase();
    if (s === "") return null;                             // vazio => ausente
    if (s === "insuficiente") return SENTINELA;            // insuficiente
    const n = Number(s.replace(",", "."));
    if (Number.isFinite(n)) return n;                      // "77"->77, "7,5"->7.5
    return SENTINELA;                                      // texto inesperado => insuficiente
  }
  return null;
};

// Todas as notas possíveis, JÁ normalizadas
const candidatas = {
  variety: normalizar(e.variety_nota),
  service: normalizar(e.service_nota),
  price_to_value: normalizar(e.price_to_value_nota),
  capacity: normalizar(e.capacity_nota),
  beauty: normalizar(e.beauty_nota),
  space: normalizar(e.space_nota),
  fun: normalizar(e.fun_nota),
  food: normalizar(e.food_nota),
};

const rotulos = {
  variety: "variedade",
  service: "atendimento",
  price_to_value: "custo-benefício",
  capacity: "capacidade",
  beauty: "beleza",
  space: "espaço",
  fun: "diversão",
  food: "comida",
};

// --------------------
// MÉDIA
// --------------------
const presentes = Object.entries(candidatas).filter(([, v]) => ehNotaValida(v));
const notasUsadas = presentes.map(([, v]) => v);
const media = notasUsadas.length
  ? notasUsadas.reduce((a, b) => a + b, 0) / notasUsadas.length
  : null;

// --------------------
// NÃO AVALIADAS (insuficientes) — agora pega "insuficiente"/77 igual
// --------------------
const notasNaoAvaliadas = Object.entries(candidatas)
  .filter(([, v]) => v === SENTINELA)
  .map(([k]) => k);

const reprovaPorInsuficientes = notasNaoAvaliadas.length > MAX_NAO_AVALIADAS;

// --------------------
// REGRAS
// --------------------
const motivos = [];
const observacoes = [];

// FOTOS (crítico)
const temFotoAnalise = Array.isArray(e.fotos_analise) && e.fotos_analise.length > 0;
if (!temFotoAnalise) {
  motivos.push("Sem fotos analisadas (fotos_analise ausente ou vazio)");
}

// FOOD (crítico) — insuficiente REPROVA; mínimo = MIN_FOOD_FUN
// Se já reprovou por >2 insuficientes, NÃO duplica o motivo de comida insuficiente.
const foodN = candidatas.food;
if (foodN !== null) {
  if (foodN === SENTINELA) {
    if (!reprovaPorInsuficientes) {
      motivos.push("Comida não pôde ser avaliada (insuficiente)");
    }
  } else if (foodN < MIN_FOOD_FUN) {
    motivos.push(`Nota de comida abaixo de ${MIN_FOOD_FUN} (food_nota=${round(foodN)})`);
  }
}

// FUN (crítico) — mínimo = MIN_FOOD_FUN
const funN = candidatas.fun;
if (funN !== null) {
  if (funN === SENTINELA) {
    if (!reprovaPorInsuficientes) {
      observacoes.push("diversão não pôde ser avaliada (insuficiente)");
    }
  } else if (funN < MIN_FOOD_FUN) {
    motivos.push(`Nota de diversão abaixo de ${MIN_FOOD_FUN} (fun_nota=${round(funN)})`);
  }
}

// NÃO AVALIADAS (crítico) — mais de 2 insuficientes => reprova
if (reprovaPorInsuficientes) {
  const nomes = notasNaoAvaliadas.map((k) => rotulos[k] || k);
  motivos.push(
    `Notas insuficientes: ${notasNaoAvaliadas.length} notas sem dados ` +
    `— máximo permitido é ${MAX_NAO_AVALIADAS} (${nomes.join(", ")})`
  );
}

// MÉDIA — não repete "sem notas válidas" se já reprovou por excesso de insuficientes
if (media === null) {
  if (!reprovaPorInsuficientes) {
    motivos.push("Sem notas qualitativas válidas para calcular a média");
  }
} else if (media < MIN) {
  motivos.push(`media das notas qualitativas abaixo do corte (${MIN})`);
}

const aprovado = motivos.length === 0;

// --------------------
// JUSTIFICATIVA
// --------------------
let motivo;

if (aprovado) {
  const partes = [`Média das notas qualitativas ${round(media)} (≥ ${MIN})`];
  if (ehNotaValida(foodN)) partes.push(`comida ${round(foodN)} (≥ ${MIN_FOOD_FUN})`);
  if (ehNotaValida(funN)) partes.push(`diversão ${round(funN)} (≥ ${MIN_FOOD_FUN})`);
  if (observacoes.length) partes.push(...observacoes);
  if (notasNaoAvaliadas.length) {
    const nomes = notasNaoAvaliadas.map((k) => rotulos[k] || k);
    partes.push(`não avaliadas: ${nomes.join(", ")}`);
  }
  motivo = "Aprovado — " + partes.join("; ");
} else {
  let txt = "Reprovado — " + motivos.join(" | ");
  if (observacoes.length) txt += " | (obs: " + observacoes.join("; ") + ")";
  motivo = txt;
}

// --------------------
// OUTPUT
// --------------------
return {
  json: {
    ...e,
    minimum_grade_usado: MIN,
    min_food_fun_usado: MIN_FOOD_FUN,
    media_qualitativa: round(media),
    notas_consideradas: notasUsadas.length,
    notas_usadas: presentes.map(([k]) => k),
    notas_nao_avaliadas: notasNaoAvaliadas,
    qtd_notas_nao_avaliadas: notasNaoAvaliadas.length,
    tem_fotos_analise: temFotoAnalise,
    aprovado_notas: aprovado,
    motivo_notas: motivo,
  }
};

