      .sort((a, b) => Number(b?.nota_capa ?? 0) - Number(a?.nota_capa ?? 0));
  }

  // --- 2. Reevaluation (objeto): mantém a média antiga, resto sobrescreve ---
  let prev = dados.Reevaluation;
  if (typeof prev === 'string' && prev.trim()) {
    try { prev = JSON.parse(prev); } catch (e) { prev = null; }
  }
  if (Array.isArray(prev) || typeof prev !== 'object') prev = null;

  // média: mantém a antiga como veio; ignora a nova
  const mediaAntiga = (prev && prev['média'] != null) ? prev['média'] : null;

  // sessao = anterior + 1 (1 na primeira vez)
  const sessaoPrev = (prev && Number.isFinite(Number(prev.sessao))) ? Number(prev.sessao) : 0;

  const agora = tsBrasil();
  dados.Reevaluation = {
    'média': mediaAntiga,                       // mantém a antiga, ignora a nova
    aproved: dados.aprovado_notas === true,     // novo (sobrescreve)
    reason: dados.motivo_notas ?? null,         // novo
    data: agora,                                // novo
    sessao: sessaoPrev + 1,                     // anterior + 1
    updated_at: agora,                          // sobrescreve com agora
  };

  item.json = dados;
}

return items;

// Lê o campo existente SEM alterá-lo, e adiciona um campo novo com frases numeradas.
const texto = $json.comentarios_formatados || "";

// 1) separa cada "Comentário N: ..." preservando o número original
const blocos = texto
  .split(/\n\s*\n/)            // comentários são separados por linha em branco
  .map(b => b.trim())
  .filter(Boolean);

const linhas = [];
let contadorFrase = 0;

for (const bloco of blocos) {
  // remove o rótulo "Comentário N:" do início, guardando o número
  const m = bloco.match(/^Coment[áa]rio\s+(\d+)\s*:\s*([\s\S]*)$/i);
  const numComentario = m ? m[1] : "?";
  const corpo = m ? m[2] : bloco;

  // 2) quebra o corpo em frases (fim de frase ou quebra de linha)
  const frases = corpo
    .split(/(?<=[.!?])\s+|\n+/)
    .map(f => f.trim())
    .filter(f => f.length > 0);

  // se o comentário não tiver pontuação, ele inteiro vira uma "frase"
  const lista = frases.length ? frases : [corpo.trim()].filter(Boolean);

  for (const f of lista) {
    contadorFrase++;
    // formato: "F12 (C10): frase isolada"
    linhas.push(`F${contadorFrase} (C${numComentario}): ${f}`);
  }
}

// adiciona o campo novo, mantém todo o resto do item intacto
$json.comentarios_frases = linhas.join("\n");

return $input.item;

// Limpa a saída dos agentes mas MANTÉM cada campo de review como STRING JSON,
// e MANTÉM os itens separados (é o que o Organizer espera receber).
// Só desembrulha {action,text} e normaliza, sem mudar a estrutura.
// Detecta automaticamente qualquer campo "*_review" + "summary", então
// funciona em qualquer fluxo (service, food, fun, beauty, etc.).

function ehCampoReview(chave) {
  return chave === "summary" || chave.endsWith("_review");
}

function limpaParaString(valor) {
  if (valor == null) return valor;
  let obj = (typeof valor === "object") ? valor : null;
  if (obj === null && typeof valor === "string") {
    try { obj = JSON.parse(valor.trim()); } catch (e) { return valor; } // não parseou: devolve como veio
  }
  if (!obj) return valor;
  // desembrulha {action:"parse", text:"{...}"}
  if (obj.text && (obj.action || obj.resultado === undefined)) {
    try {
      const inner = JSON.parse(obj.text);
      if (inner && (inner.resultado !== undefined || inner.id !== undefined)) obj = inner;
    } catch (e) {}
  }
  // re-serializa como string JSON limpa { id, resultado }
  return JSON.stringify({
    id: obj.id ?? null,
    resultado: obj.resultado ?? null
  });
}

const out = [];
for (const item of $input.all()) {
  const novo = { ...item.json };
  for (const campo of Object.keys(novo)) {
    if (ehCampoReview(campo) && novo[campo] !== undefined) {
      novo[campo] = limpaParaString(novo[campo]);
    }
  }
  out.push({ json: novo });
}
return out;

